# Combined Segmentation and Paging with TLB

# System Configuration
SEGMENT_SIZE = 1024    # Max segment size (for segment number bits)
PAGE_SIZE = 64         # Page size within segments
PAGES_PER_SEG = 16     # Pages per segment
TLB_SIZE = 4           # TLB entries

# Global Page Table (for each segment, a page table)
global_page_table = {
    0: {0: 8, 1: 3, 2: 11, 3: -1},   # Segment 0 page table
    1: {0: 5, 1: 9, 2: -1, 3: 2},   # Segment 1 page table
    2: {0: 7, 1: 1, 2: 6, 3: 4},   # Segment 2 page table
}

# Segment Table
segment_table = {
    0: {"base": 0, "limit": 1024},
    1: {"base": 0, "limit": 1024},
    2: {"base": 0, "limit": 1024},
}

# TLB Cache: stores (segment, page) -> frame translations
tlb = {}
tlb_hits = 0
tlb_misses = 0

def translate_address_tlb(segment, page, offset):
    """Translate address using segmentation + paging with TLB."""
    global tlb_hits, tlb_misses

    # Step 1: Validate segment
    if segment not in segment_table:
        return {"error": "Invalid segment"}

    if offset >= PAGE_SIZE:
        return {"error": "Offset exceeds page size"}

    # Step 2: Check TLB first
    tlb_key = (segment, page)

    if tlb_key in tlb:
        tlb_hits += 1
        frame = tlb[tlb_key]
        return {
            "physical": frame * PAGE_SIZE + offset,
            "source": "TLB Hit",
            "frame": frame
        }

    # TLB miss - consult page table
    tlb_misses += 1

    if segment not in global_page_table:
        return {"error": "Segment not in page table"}

    page_table = global_page_table[segment]

    if page not in page_table:
        return {"error": "Page fault - page not in memory"}

    frame = page_table[page]

    if frame == -1:
        return {"error": f"Page fault - page {page} not in memory"}

    # Add to TLB (with simple eviction if full)
    if len(tlb) >= TLB_SIZE:
        # Remove first entry (FIFO)
        evicted_key = next(iter(tlb))
        del tlb[evicted_key]
        print(f"  [TLB] Evicted segment {evicted_key[0]}, page {evicted_key[1]}")

    tlb[tlb_key] = frame

    return {
        "physical": frame * PAGE_SIZE + offset,
        "source": "Page Table",
        "frame": frame
    }

def display_tlb():
    """Display current TLB contents."""
    print("\n[TLB Contents]")
    for (seg, page), frame in tlb.items():
        print(f"  Segment {seg}, Page {page} -> Frame {frame}")
    print(f"[Stats] Hits: {tlb_hits}, Misses: {tlb_misses}")

# Demo
print("=== Combined Segmentation + Paging with TLB ===\n")
print(f"Segment Size: {SEGMENT_SIZE}, Page Size: {PAGE_SIZE}")
print(f"Pages per Segment: {PAGES_PER_SEG}, TLB Size: {TLB_SIZE}\n")

test_addresses = [
    (0, 0, 10),   # Seg 0, Page 0, Offset 10
    (0, 1, 20),   # Seg 0, Page 1, Offset 20
    (1, 0, 30),   # Seg 1, Page 0, Offset 30
    (0, 0, 10),   # Same as first - TLB hit
    (2, 2, 40),   # Seg 2, Page 2, Offset 40
    (1, 1, 50),   # Seg 1, Page 1, Offset 50
    (0, 2, 60),   # Seg 0, Page 2, Offset 60
    (2, 3, 70),   # Seg 2, Page 3 - Page fault!
    (1, 2, 80),   # Seg 1, Page 2 - Page fault!
]

for seg, page, offset in test_addresses:
    print(f"Translate: Seg={seg}, Page={page}, Offset={offset}")
    result = translate_address_tlb(seg, page, offset)

    if "error" in result:
        print(f"  Result: {result['error']}")
    else:
        print(f"  Physical: {result['physical']}, Frame: {result['frame']}, Source: {result['source']}")

    if len(tlb) >= TLB_SIZE and tlb_misses > tlb_hits:
        display_tlb()
    print()

print("\n=== Final TLB State ===")
display_tlb()
